import { Component,OnInit,ChangeDetectorRef } from '@angular/core';
import { DonorService } from '../../Services/DonorService';
import { Donor } from '../../Services/DonorService';
import { Observable } from 'rxjs';
import { DonorModel } from '../../Models/Donor';
import { TableModule } from 'primeng/table';
import { BrowserAnimationsModule } from '@angular/platform-browser/animations';
import { CommonModule } from '@angular/common';


@Component({
  selector: 'app-donors-comp',
    standalone: true,  
  imports: [TableModule, CommonModule],
  templateUrl: './donors-comp.html',
  styleUrls: ['./donors-comp.scss'],
})
export class DonorsComp implements OnInit {

  donors: Donor[] = [];
  loading: boolean = true;
  constructor(private donorService: DonorService) { }


    ngOnInit() {
      alert("Welcome to the Donors Page!");
    this.donorService.getAllDonors().subscribe({
      next: (res) => {
        setTimeout(() => {
          console.log("Data received:", res);
          this.donors = res;
          this.loading = false;
        }, 0);
      },
      error: (err) => {
        console.error(err);
        this.loading = false;
      }
    });

}
}
<p>donors-comp works!</p>


<p-table [value]="donors" [paginator]="true" [rows]="10" [loading]="loading" [responsiveLayout]="'scroll'">
  <ng-template pTemplate="header">
    <tr>
      <th>ID</th>
      <th>firstName</th>
      <th>lastName</th>
      <th>Email</th>
      <th>Phone</th>
    </tr>
  </ng-template>

  <ng-template pTemplate="body" let-donor>
    <tr>
      <td>{{ donor.id }}</td>
      <td>{{ donor.firstName }}</td>
      <td>{{ donor.lastName }}</td>
      <td>{{ donor.email  }}</td>
      <td>{{ donor.phone }}</td>
    </tr>
  </ng-template>
</p-table>
